operations.reducer:
state.operatorProfile = {
    id: action.input.operatorId,
    documentType: action.input.operatorDocumentType
};
state.resourceTemplateId = action.input.resourceTemplateId || null;
state.customerId = action.input.customerId || null;
state.customerName = action.input.customerName || null;
state.templateName = action.input.templateName || null;
state.operatorName = action.input.operatorName || null;
state.name = action.input.name || null;
state.thumbnailUrl = action.input.thumbnailUrl || null;
state.infoLink = action.input.infoLink || null;
state.description = action.input.description || null;
state.status = "DRAFT";

operations.schema:
input UpdateInstanceInfoInput {
    name: String
    thumbnailUrl: URL
    infoLink: URL
    description: String
}

operations.reducer:
if (action.input.name) state.name = action.input.name;
if (action.input.thumbnailUrl) state.thumbnailUrl = action.input.thumbnailUrl;
if (action.input.infoLink) state.infoLink = action.input.infoLink;
if (action.input.description) state.description = action.input.description;

operations.schema:
input SetOperatorProfileInput {
    operatorId: PHID!
    operatorName: String
}

operations.reducer:
if (state.status !== "DRAFT") {
    throw new InvalidStatusTransitionError("Can only confirm instances in DRAFT status");
}
state.status = "PROVISIONING";
state.confirmedAt = action.input.confirmedAt;

if (state.status !== "PROVISIONING") {
    throw new InvalidStatusTransitionReportProvisioningStartedError("Can only report provisioning started for instances in PROVISIONING status");
}
state.provisioningStartedAt = action.input.startedAt;

if (state.status !== "PROVISIONING") {
    throw new InvalidStatusTransitionReportProvisioningCompletedError("Can only report provisioning completed for instances in PROVISIONING status");
}
state.provisioningCompletedAt = action.input.completedAt;

operations.schema:
input ReportProvisioningFailedInput {
    failedAt: DateTime!
    failureReason: String!
}

operations.reducer:
if (state.status !== "PROVISIONING") {
    throw new InvalidStatusTransitionReportProvisioningFailedError("Can only report provisioning failed for instances in PROVISIONING status");
}
state.provisioningFailureReason = action.input.failureReason;
state.status = "DRAFT";

if (state.status !== "PROVISIONING") {
    throw new InvalidStatusTransitionActivateInstanceError("Can only activate instances in PROVISIONING status");
}
if (!state.provisioningCompletedAt) {
    throw new ProvisioningNotCompletedError("Must report provisioning completed before activating");
}
state.status = "ACTIVE";
state.activatedAt = action.input.activatedAt;

operations.schema:
input SuspendForNonPaymentInput {
    suspendedAt: DateTime!
    outstandingAmount: Amount_Money
    daysPastDue: Int
}

operations.reducer:
if (state.status !== "ACTIVE") {
    throw new InvalidStatusTransitionSuspendForNonPaymentError("Can only suspend ACTIVE instances");
}
state.status = "SUSPENDED";
state.suspendedAt = action.input.suspendedAt;
state.suspensionType = "NON_PAYMENT";
state.suspensionReason = "Non-payment";
const details = [];
if (action.input.outstandingAmount) {
    details.push(`Outstanding: ${action.input.outstandingAmount}`);
}
if (action.input.daysPastDue) {
    details.push(`Days past due: ${action.input.daysPastDue}`);
}
state.suspensionDetails = details.join(", ") || null;

operations.schema:
input SuspendForMaintenanceInput {
    suspendedAt: DateTime!
    estimatedDuration: String
    maintenanceType: String
}

operations.reducer:
if (state.status !== "ACTIVE") {
    throw new InvalidStatusTransitionSuspendForMaintenanceError("Can only suspend ACTIVE instances");
}
state.status = "SUSPENDED";
state.suspendedAt = action.input.suspendedAt;
state.suspensionType = "MAINTENANCE";
state.suspensionReason = "Scheduled maintenance";
const details = [];
if (action.input.maintenanceType) {
    details.push(`Type: ${action.input.maintenanceType}`);
}
if (action.input.estimatedDuration) {
    details.push(`Duration: ${action.input.estimatedDuration}`);
}
state.suspensionDetails = details.join(", ") || null;

operations.schema:
input ResumeAfterPaymentInput {
    resumedAt: DateTime!
    paymentReference: String
}

operations.reducer:
if (state.status !== "SUSPENDED") {
    throw new InvalidStatusTransitionResumeAfterPaymentError("Can only resume SUSPENDED instances");
}
if (state.suspensionType !== "NON_PAYMENT") {
    throw new InvalidSuspensionTypeError("This operation is for NON_PAYMENT suspensions only");
}
state.status = "ACTIVE";
state.resumedAt = action.input.resumedAt;

if (state.status !== "SUSPENDED") {
    throw new InvalidStatusTransitionResumeAfterMaintenanceError("Can only resume SUSPENDED instances");
}
if (state.suspensionType !== "MAINTENANCE") {
    throw new InvalidSuspensionTypeResumeAfterMaintenanceError("This operation is for MAINTENANCE suspensions only");
}
state.status = "ACTIVE";
state.resumedAt = action.input.resumedAt;

operations.schema:
input SuspendInstanceInput {
    suspendedAt: DateTime!
    reason: String
}

operations.reducer:
if (state.status !== "ACTIVE") {
    throw new InvalidStatusTransitionSuspendInstanceError("Can only suspend ACTIVE instances");
}
state.status = "SUSPENDED";
state.suspendedAt = action.input.suspendedAt;
state.suspensionType = "OTHER";
state.suspensionReason = action.input.reason || null;

operations.schema:
input TerminateInstanceInput {
    terminatedAt: DateTime!
    reason: String!
}

operations.reducer:
if (state.status === "TERMINATED") {
    throw new AlreadyTerminatedError("Instance is already terminated and cannot be terminated again");
}
state.status = "TERMINATED";
state.terminatedAt = action.input.terminatedAt;
state.terminationReason = action.input.reason;

operations.schema:
input SetInstanceFacetInput {
    id: OID!
    categoryKey: String!
    categoryLabel: String!
    selectedOption: String!
}

operations.reducer:
if (state.status === "ACTIVE") {
    throw new ConfigurationLockedError("Cannot modify configuration while instance is ACTIVE");
}
const existingIndex = state.configuration.findIndex(c => c.categoryKey === action.input.categoryKey);
if (existingIndex !== -1) {
    state.configuration[existingIndex] = {
        id: action.input.id,
        categoryKey: action.input.categoryKey,
        categoryLabel: action.input.categoryLabel,
        selectedOption: action.input.selectedOption
    };
} else {
    state.configuration.push({
        id: action.input.id,
        categoryKey: action.input.categoryKey,
        categoryLabel: action.input.categoryLabel,
        selectedOption: action.input.selectedOption
    });
}

if (state.status === "ACTIVE") {
    throw new ConfigurationLockedRemoveInstanceFacetError("Cannot modify configuration while instance is ACTIVE");
}
const facetIndex = state.configuration.findIndex(c => c.categoryKey === action.input.categoryKey);
if (facetIndex !== -1) {
    state.configuration.splice(facetIndex, 1);
}

operations.schema:
input UpdateInstanceFacetInput {
    categoryKey: String!
    selectedOption: String
    categoryLabel: String
}

operations.reducer:
if (state.status === "ACTIVE") {
    throw new ConfigurationLockedUpdateInstanceFacetError("Cannot modify configuration while instance is ACTIVE");
}
const facetIndex = state.configuration.findIndex(c => c.categoryKey === action.input.categoryKey);
if (facetIndex !== -1) {
    if (action.input.selectedOption) {
        state.configuration[facetIndex].selectedOption = action.input.selectedOption;
    }
    if (action.input.categoryLabel) {
        state.configuration[facetIndex].categoryLabel = action.input.categoryLabel;
    }
}

if (state.status === "ACTIVE") {
    throw new ConfigurationLockedApplyConfigurationChangesError("Cannot modify configuration while instance is ACTIVE. Suspend the instance first.");
}
action.input.removeFacetKeys?.forEach(categoryKey => {
    const index = state.configuration.findIndex(f => f.categoryKey === categoryKey);
    if (index !== -1) state.configuration.splice(index, 1);
});
action.input.updateFacets?.forEach(update => {
    const facet = state.configuration.find(f => f.categoryKey === update.categoryKey);
    if (facet) {
        if (update.selectedOption) facet.selectedOption = update.selectedOption;
        if (update.categoryLabel) facet.categoryLabel = update.categoryLabel;
    }
});
action.input.addFacets?.forEach(newFacet => {
    state.configuration.push({
        id: newFacet.id,
        categoryKey: newFacet.categoryKey,
        categoryLabel: newFacet.categoryLabel,
        selectedOption: newFacet.selectedOption
    });
});
